class RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that only allows loading known safe classes.
    This prevents arbitrary code execution via crafted pickle files.
    """

    def find_class(self, module: str, name: str) -> Any:
        # Check if module is explicitly blocked
        module_root = module.split(".")[0]
        if module in BLOCKED_MODULES or module_root in BLOCKED_MODULES:
            raise pickle.UnpicklingError(
                f"Blocked attempt to load '{module}.{name}' - module is not allowed"
            )

        # Check against allowlist
        if module in ALLOWED_MODULES_CLASSES:
            allowed_classes = ALLOWED_MODULES_CLASSES[module]
            if "*" in allowed_classes or name in allowed_classes:
                return super().find_class(module, name)

        raise pickle.UnpicklingError(
            f"Blocked attempt to load '{module}.{name}' - not in allowlist. "
            f"Only approved sklearn models and related types are permitted."
        )


def safe_pickle_load(file_bytes: bytes) -> Any:
    """Safely load a pickle file using the restricted unpickler."""
    return RestrictedUnpickler(io.BytesIO(file_bytes)).load()


