def get_tenant_id(credentials: HTTPAuthorizationCredentials = Depends(security)) -> str:
    """Validate API key and return tenant ID."""
    token = credentials.credentials
    tenant_id = TENANT_API_KEYS.get(token)
    if tenant_id is None:
        raise HTTPException(status_code=401, detail="Invalid API key")
    return tenant_id


# --- Helper Functions ---

def compute_file_hash(file_bytes: bytes) -> str:
    """Compute SHA-256 hash of file contents."""
    return hashlib.sha256(file_bytes).hexdigest()


def validate_model_has_predict(model: Any) -> bool:
    """Check if the loaded object has a predict method."""
    return hasattr(model, "predict") and callable(getattr(model, "predict"))


def get_model_type_name(model: Any) -> str:
    """Get a human-readable model type name."""
    return type(model).__module__ + "." + type(model).__name__


