@app.post("/models/upload", response_model=ModelInfo)
async def upload_model(
    file: UploadFile = File(...),
    model_name: str = Form(...),
    tenant_id: str = Depends(get_tenant_id),
):
    """
    Upload a pickled sklearn model file.
    
    The model is deserialized using a restricted unpickler that only allows
    known safe sklearn classes, preventing arbitrary code execution.
    """
    # Validate file extension
    if not file.filename.endswith((".pkl", ".pickle", ".joblib")):
        raise HTTPException(
            status_code=400,
            detail="Only .pkl, .pickle, or .joblib files are accepted",
        )

    # Check tenant model limit
    tenant_model_count = len(tenant_models.get(tenant_id, {}))
    if tenant_model_count >= MAX_MODELS_PER_TENANT:
        raise HTTPException(
            status_code=429,
            detail=f"Tenant has reached maximum model limit of {MAX_MODELS_PER_TENANT}",
        )

    # Read file contents with size limit
    file_bytes = await file.read()
    if len(file_bytes) > MAX_MODEL_SIZE_BYTES:
        raise HTTPException(
            status_code=413,
            detail=f"File size exceeds maximum allowed size of {MAX_MODEL_SIZE_BYTES // (1024*1024)} MB",
        )

    if len(file_bytes) == 0:
        raise HTTPException(status_code=400, detail="Uploaded file is empty")

    # Compute file hash
    file_hash = compute_file_hash(file_bytes)

    # Check for duplicate uploads for this tenant
    if tenant_id in tenant_models:
        for existing_model in tenant_models[tenant_id].values():
            if existing_model["file_hash"] == file_hash:
                raise HTTPException(
                    status_code=409,
                    detail=f"This model file has already been uploaded as '{existing_model['model_name']}' (ID: {existing_model['model_id']})",
                )

    # Safely deserialize the model using restricted unpickler
    try:
        model = safe_pickle_load(file_bytes)
    except pickle.UnpicklingError as e:
        raise HTTPException(
            status_code=400,
            detail=f"Model deserialization blocked for security reasons: {str(e)}",
        )
    except Exception as e:
        raise HTTPException(
            status_code=400,
            detail=f"Failed to load model file: {str(e)}",
        )

    # Validate that the model has a predict method
    if not validate_model_has_predict(model):
        raise HTTPException(
            status_code=400,
            detail="Uploaded model does not have a 'predict' method. Only sklearn-compatible models are supported.",
        )

    model_type = get_model_type_name(model)

    # Generate unique model ID
    model_id = str(uuid.uuid4())

    # Store model file to disk (tenant-isolated directory)
    tenant_dir = os.path.join(UPLOAD_DIR, tenant_id)
    os.makedirs(tenant_dir, exist_ok=True)
    model_path = os.path.join(tenant_dir, f"{model_id}.pkl")

    with open(model_path, "wb") as f:
        f.write(file_bytes)

    # Store model metadata and loaded model object
    if tenant_id not in tenant_models:
        tenant_models[tenant_id] = {}

    model_info = {
        "model_id": model_id,
        "model_name": model_name,
        "uploaded_at": datetime.utcnow().isoformat(),
        "file_size_bytes": len(file_bytes),
        "file_hash": file_hash,
        "model_type": model_type,
        "model_path": model_path,
        "model_object": model,
    }

    tenant_models[tenant_id][model_id] = model_info

    return ModelInfo(
        model_id=model_id,
        model_name=model_name,
        uploaded_at=model_info["uploaded_at"],
        file_size_bytes=len(file_bytes),
        file_hash=file_hash,
        model_type=model_type,
    )


@app.post("/models/predict", response_model=InferenceResponse)
async def predict(
    request: InferenceRequest,
    tenant_id: str = Depends(get_tenant_id),
):
    """
    Run inference using an uploaded model.
    
    Input data should be in a format compatible with the model's predict method
    (typically a 2D array/list of lists for sklearn models).
    """
    # Check if tenant has any models
    if tenant_id not in tenant_models or request.model_id not in tenant_models[tenant_id]:
        raise HTTPException(
            status_code=404,
            detail=f"Model '{request.model_id}' not found for this tenant",
        )

    model_info = tenant_models[tenant_id][request.model_id]
    model = model_info["model_object"]

    # Convert input data to numpy array
    try:
        if isinstance(request.input_data, dict):
            # Handle dict input (e.g., for pandas DataFrame-like input)
            import pandas as pd
            input_array = pd.DataFrame(request.input_data)
        elif isinstance(request.input_data, list):
            input_array = np.array(request.input_data)
            # Ensure 2D array for sklearn
            if input_array.ndim == 1:
                input_array = input_array.reshape(1, -1)
        else:
            raise ValueError("Input data must be a list or dict")
    except Exception as e:
        raise HTTPException(
            status_code=400,
            detail=f"Failed to parse input data: {str(e)}",
        )

    # Run inference
    try:
        predictions = model.predict(input_array)
        # Convert numpy types to Python native types for JSON serialization
        if isinstance(predictions, np.ndarray):
            predictions = predictions.tolist()
    except Exception as e:
        raise HTTPException(
            status_code=500,
            detail=f"Inference failed: {str(e)}",
        )

    return InferenceResponse(
        model_id=request.model_id,
        predictions=predictions,
        model_name=model_info["model_name"],
    )


@app.get("/models", response_model=ModelListResponse)
async def list_models(tenant_id: str = Depends(get_tenant_id)):
    """List all models for the authenticated tenant."""
    models = []
    if tenant_id in tenant_models:
        for model_info in tenant_models[tenant_id].values():
            models.append(
                ModelInfo(
                    model_id=model_info["model_id"],
                    model_name=model_info["model_name"],
                    uploaded_at=model_info["uploaded_at"],
                    file_size_bytes=model_info["file_size_bytes"],
                    file_hash=model_info["file_hash"],
                    model_type=model_info.get("model_type"),
                )
            )

    return ModelListResponse(
        tenant_id=tenant_id,
        models=models,
        total_count=len(models),
    )


@app.get("/models/{model_id}", response_model=ModelInfo)
async def get_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Get details about a specific model."""
    if tenant_id not in tenant_models or model_id not in tenant_models[tenant_id]:
        raise HTTPException(
            status_code=404,
            detail=f"Model '{model_id}' not found for this tenant",
        )

    model_info = tenant_models[tenant_id][model_id]
    return ModelInfo(
        model_id=model_info["model_id"],
        model_name=model_info["model_name"],
        uploaded_at=model_info["uploaded_at"],
        file_size_bytes=model_info["file_size_bytes"],
        file_hash=model_info["file_hash"],
        model_type=model_info.get("model_type"),
    )


@app.delete("/models/{model_id}")
async def delete_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Delete a model."""
    if tenant_id not in tenant_models or model_id not in tenant_models[tenant_id]:
        raise HTTPException(
            status_code=404,
            detail=f"Model '{model_id}' not found for this tenant",
        )

    model_info = tenant_models[tenant_id][model_id]

    # Remove file from disk
    model_path = model_info.get("model_path")
    if model_path and os.path.exists(model_path):
        os.remove(model_path)

    # Remove from memory
    del tenant_models[tenant_id][model_id]

    return {"message": f"Model '{model_id}' deleted successfully"}


